unit lipdecide;

{$mode objfpc}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

const
  EPSILON_COMP = 1e-6;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale: real;
  scaledA, scaledB: real;
  diff: real;
begin
  { Find the scale based on the larger magnitude }
  if Abs(A) > Abs(B) then
    scale := Abs(A)
  else
    scale := Abs(B);

  { If both numbers are very close to zero, treat as equal }
  if scale < EPSILON_COMP then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  { Scale both numbers to 6 significant digits and compare }
  scaledA := A / scale;
  scaledB := B / scale;

  { Now compare the scaled values with appropriate epsilon }
  diff := scaledA - scaledB;

  if diff > EPSILON_COMP then
    REALCOMPARE := GT
  else if diff < -EPSILON_COMP then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := Sqrt(Sqr(x2 - x1) + Sqr(y2 - y1));
end;

{ Check if three points can be contained within or on a circle of radius R }
function CanFitInCircle(x1, y1, x2, y2, x3, y3, R: real): boolean;
var
  d12, d13, d23: real;
  a, b, c: real;
  circumRadius: real;
  d: real;
  centerX, centerY: real;
  maxDist: real;
  distToCenter: real;
begin
  { Calculate side lengths }
  d12 := Distance(x1, y1, x2, y2);
  d13 := Distance(x1, y1, x3, y3);
  d23 := Distance(x2, y2, x3, y3);

  { Find the largest side }
  if (d12 >= d13) and (d12 >= d23) then
  begin
    a := d12;
    b := d13;
    c := d23;
  end
  else if (d13 >= d12) and (d13 >= d23) then
  begin
    a := d13;
    b := d12;
    c := d23;
  end
  else
  begin
    a := d23;
    b := d12;
    c := d13;
  end;

  { If all points are the same, any circle with radius >= 0 contains them }
  if (REALCOMPARE(a, 0) = EQ) and (REALCOMPARE(b, 0) = EQ) then
  begin
    CanFitInCircle := (REALCOMPARE(R, 0) <> LT);
    Exit;
  end;

  { If points are collinear (degenerate triangle), find min enclosing circle }
  { For collinear points, the diameter equals the largest distance }
  { Check if points are collinear using area of triangle }
  d := Abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1));
  if REALCOMPARE(d, 0) = EQ then
  begin
    { Points are collinear - min enclosing circle has diameter = largest distance }
    if REALCOMPARE(a / 2, R) = GT then
      CanFitInCircle := False
    else
      CanFitInCircle := True;
    Exit;
  end;

  { For non-degenerate triangle, calculate circumradius }
  { R_circum = (a * b * c) / (4 * Area) }
  { Area = 0.5 * |cross product| }
  circumRadius := (d12 * d13 * d23) / (2 * d);

  { If circumradius fits in circle, all points are inside }
  if REALCOMPARE(circumRadius, R) = GT then
    CanFitInCircle := False
  else
    CanFitInCircle := True;
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := 0.5 * Abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)));
end;

function GetQuadrant(x, y: real): integer;
begin
  { Priority: I, II, III, IV }
  if (REALCOMPARE(x, 0) <> LT) and (REALCOMPARE(y, 0) <> LT) then
    GetQuadrant := 1
  else if (REALCOMPARE(x, 0) = LT) and (REALCOMPARE(y, 0) <> LT) then
    GetQuadrant := 2
  else if (REALCOMPARE(x, 0) = LT) and (REALCOMPARE(y, 0) = LT) then
    GetQuadrant := 3
  else if (REALCOMPARE(x, 0) <> LT) and (REALCOMPARE(y, 0) = LT) then
    GetQuadrant := 4
  else
    GetQuadrant := 1; { Default to I if x >= 0 and y < 0 but x = 0 }
end;

function ComputeAngle(x1, y1, x2, y2, x3, y3: real): real;
{ Computes angle at vertex (x2, y2) formed by rays to (x1,y1) and (x3,y3) }
var
  v1x, v1y, v2x, v2y: real;
  len1, len2: real;
  dot: real;
  cosAngle: real;
begin
  { Vectors from vertex to other points }
  v1x := x1 - x2;
  v1y := y1 - y2;
  v2x := x3 - x2;
  v2y := y3 - y2;

  len1 := Sqrt(v1x * v1x + v1y * v1y);
  len2 := Sqrt(v2x * v2x + v2y * v2y);

  { If either vector is zero, angle is undefined }
  if (REALCOMPARE(len1, 0) = EQ) or (REALCOMPARE(len2, 0) = EQ) then
  begin
    ComputeAngle := -1; { Undefined }
    Exit;
  end;

  { Normalize and compute dot product }
  dot := (v1x * v2x + v1y * v2y);
  cosAngle := dot / (len1 * len2);

  { Clamp to [-1, 1] to handle floating point errors }
  if REALCOMPARE(cosAngle, 1) = GT then
    cosAngle := 1
  else if REALCOMPARE(cosAngle, -1) = LT then
    cosAngle := -1;

  ComputeAngle := ArcCos(cosAngle);
end;

function DistanceToLine(px, py, x1, y1, x2, y2: real): real;
{ Distance from point (px, py) to line through (x1,y1) and (x2,y2) }
var
  num, den: real;
begin
  den := Sqrt(Sqr(x2 - x1) + Sqr(y2 - y1));
  if REALCOMPARE(den, 0) = EQ then
  begin
    { Line is a point - return distance to that point }
    DistanceToLine := Sqrt(Sqr(px - x1) + Sqr(py - y1));
    Exit;
  end;
  num := Abs((y2 - y1) * px - (x2 - x1) * py + x2 * y1 - y2 * x1);
  DistanceToLine := num / den;
end;

procedure EvaluateLIC1;
var
  i: integer;
  d: real;
begin
  CMV[1] := False;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := Distance(X[i], Y[i], X[i + 1], Y[i + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC2;
var
  i: integer;
begin
  CMV[2] := False;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not CanFitInCircle(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], PARAMETERS.RADIUS1) then
    begin
      CMV[2] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC3;
var
  i: integer;
  angle: real;
  lowerBound, upperBound: real;
begin
  CMV[3] := False;
  if NUMPOINTS < 3 then Exit;
  lowerBound := PI - PARAMETERS.EPSILON;
  upperBound := PI + PARAMETERS.EPSILON;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := ComputeAngle(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if angle < 0 then Continue; { Undefined angle }
    if (REALCOMPARE(angle, lowerBound) = LT) or (REALCOMPARE(angle, upperBound) = GT) then
    begin
      CMV[3] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC4;
var
  i: integer;
  area: real;
begin
  CMV[4] := False;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC5;
var
  i, j, q: integer;
  quadsUsed: array[1..4] of boolean;
  numQuadsUsed: integer;
  quad: integer;
begin
  CMV[5] := False;
  if NUMPOINTS < PARAMETERS.Q_PTS then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for q := 1 to 4 do quadsUsed[q] := False;
    for j := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      quad := GetQuadrant(X[i + j], Y[i + j]);
      quadsUsed[quad] := True;
    end;
    numQuadsUsed := 0;
    for q := 1 to 4 do if quadsUsed[q] then Inc(numQuadsUsed);
    if numQuadsUsed > PARAMETERS.QUADS then
    begin
      CMV[5] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC6;
var
  i: integer;
begin
  CMV[6] := False;
  for i := 2 to NUMPOINTS do
  begin
    if REALCOMPARE(X[i] - X[i - 1], 0) = LT then
    begin
      CMV[6] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC7;
var
  i, j: integer;
  d: real;
  x1, y1, x2, y2: real;
begin
  CMV[7] := False;
  if NUMPOINTS < 3 then Exit;
  if PARAMETERS.N_PTS > NUMPOINTS then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    x1 := X[i];
    y1 := Y[i];
    x2 := X[i + PARAMETERS.N_PTS - 1];
    y2 := Y[i + PARAMETERS.N_PTS - 1];
    for j := 1 to PARAMETERS.N_PTS - 1 do
    begin
      if (REALCOMPARE(x1, x2) = EQ) and (REALCOMPARE(y1, y2) = EQ) then
        d := Distance(X[i + j], Y[i + j], x1, y1)
      else
        d := DistanceToLine(X[i + j], Y[i + j], x1, y1, x2, y2);
      if REALCOMPARE(d, PARAMETERS.DIST) = GT then
      begin
        CMV[7] := True;
        Exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC8;
var
  i: integer;
  d: real;
  j: integer;
begin
  CMV[8] := False;
  if NUMPOINTS < 3 then Exit;
  if PARAMETERS.K_PTS > NUMPOINTS - 2 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    d := Distance(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[8] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC9;
var
  i, j, k: integer;
  angle: real;
  lowerBound, upperBound: real;
begin
  CMV[9] := False;
  if NUMPOINTS < 5 then Exit;
  if PARAMETERS.A_PTS + PARAMETERS.B_PTS > NUMPOINTS - 3 then Exit;
  lowerBound := PI - PARAMETERS.EPSILON;
  upperBound := PI + PARAMETERS.EPSILON;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if not CanFitInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
    begin
      CMV[9] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC10;
var
  i, j, k: integer;
  angle: real;
  lowerBound, upperBound: real;
begin
  CMV[10] := False;
  if NUMPOINTS < 5 then Exit;
  if PARAMETERS.C_PTS + PARAMETERS.D_PTS > NUMPOINTS - 3 then Exit;
  lowerBound := PI - PARAMETERS.EPSILON;
  upperBound := PI + PARAMETERS.EPSILON;
  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    angle := ComputeAngle(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if angle < 0 then Continue;
    if (REALCOMPARE(angle, lowerBound) = LT) or (REALCOMPARE(angle, upperBound) = GT) then
    begin
      CMV[10] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC11;
var
  i, j, k: integer;
  area: real;
begin
  CMV[11] := False;
  if NUMPOINTS < 5 then Exit;
  if PARAMETERS.E_PTS + PARAMETERS.F_PTS > NUMPOINTS - 3 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[11] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC12;
var
  i, j: integer;
begin
  CMV[12] := False;
  if NUMPOINTS < 3 then Exit;
  if PARAMETERS.G_PTS > NUMPOINTS - 2 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[j] - X[i], 0) = LT then
    begin
      CMV[12] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC13;
var
  i, j: integer;
  d: real;
  foundGreater, foundLess: boolean;
begin
  CMV[13] := False;
  if NUMPOINTS < 3 then Exit;
  if PARAMETERS.K_PTS > NUMPOINTS - 2 then Exit;
  foundGreater := False;
  foundLess := False;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    d := Distance(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      foundGreater := True;
    if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
      foundLess := True;
    if foundGreater and foundLess then
    begin
      CMV[13] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC14;
var
  i, j, k: integer;
  foundCannotFit, foundCanFit: boolean;
begin
  CMV[14] := False;
  if NUMPOINTS < 5 then Exit;
  if PARAMETERS.A_PTS + PARAMETERS.B_PTS > NUMPOINTS - 3 then Exit;
  foundCannotFit := False;
  foundCanFit := False;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if not CanFitInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
      foundCannotFit := True;
    if CanFitInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS2) then
      foundCanFit := True;
    if foundCannotFit and foundCanFit then
    begin
      CMV[14] := True;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC15;
var
  i, j, k: integer;
  area: real;
  foundGreater, foundLess: boolean;
begin
  CMV[15] := False;
  if NUMPOINTS < 5 then Exit;
  if PARAMETERS.E_PTS + PARAMETERS.F_PTS > NUMPOINTS - 3 then Exit;
  foundGreater := False;
  foundLess := False;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      foundGreater := True;
    if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
      foundLess := True;
    if foundGreater and foundLess then
    begin
      CMV[15] := True;
      Exit;
    end;
  end;
end;

procedure ComputePUM;
var
  i, j: integer;
  val: boolean;
begin
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then Continue; { Diagonal is input, don't change }
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := True;
        ANDD:    PUM[i, j] := CMV[i] and CMV[j];
        ORR:     PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
  end;
end;

procedure ComputeFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      FUV[i] := True;
      Continue;
    end;
    allTrue := True;
    for j := 1 to 15 do
    begin
      if not PUM[i, j] then
      begin
        allTrue := False;
        Break;
      end;
    end;
    FUV[i] := allTrue;
  end;
end;

procedure ComputeLAUNCH;
var
  i: integer;
begin
  LAUNCH := True;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := False;
      Exit;
    end;
  end;
end;

procedure DECIDE;
begin
  { Evaluate all 15 LICs }
  EvaluateLIC1;
  EvaluateLIC2;
  EvaluateLIC3;
  EvaluateLIC4;
  EvaluateLIC5;
  EvaluateLIC6;
  EvaluateLIC7;
  EvaluateLIC8;
  EvaluateLIC9;
  EvaluateLIC10;
  EvaluateLIC11;
  EvaluateLIC12;
  EvaluateLIC13;
  EvaluateLIC14;
  EvaluateLIC15;

  { Compute PUM from LCM and CMV }
  ComputePUM;

  { Compute FUV from PUM }
  ComputeFUV;

  { Compute final LAUNCH decision }
  ComputeLAUNCH;
end;

end.
